public String simplifyPath(String path) {
    String[] parts = path.split("/");
    LinkedList<String> stack = new LinkedList<>();

    for (String part : parts) {
        if (part.isEmpty() || part.equals(".")) continue;
        if (part.equals("..")) {
            if (!stack.isEmpty()) stack.removeLast();
        } else {
            stack.addLast(part);
        }
    }

